-- 会议列表中无法查看下属创建的计划草稿状态的数据
UPDATE `page_lists` SET `external_condition` = 'from django.db import models as djm\nfrom orionbase.common import models\nfrom orionbase.middelware.common import get_request\nfrom orion.position.position import in_positions_regex\nfrom orionbase.common.orion_function import get_user\ndef get_condition(metadata_user, page_list):\n    if get_request() and get_request().GET:\n        popup = get_request().GET.get(\'popup\', None)\n        if not popup:\n            user = get_user()\n            position_ids = user.positions_ids\n            regex = in_positions_regex(position_ids)\n            query = djm.Q(path__iregex=regex)\n            subs = models.Positions.advance_objects.filter(query).values_list(\'id\', flat=True)\n            record_types = [\n                \'city\',\'cs_bbs_meeting\',\'cs_department\',\'cs_expert_consultant_meeting\',\'cs_market\',\n                \'cs_medicine_meeting\',\'cs_patient_education_meeting\',\'cs_satellite_meeting\',\'cs_tranning\'\n            ]\n            state_ids = [\'save\']\n            condition = ~djm.Q(record_type__name__in=record_types,state__name__in=state_ids,position__in=subs)\n            return condition\n        else:\n            return None\n    else:\n        return None' WHERE (`id` = '1013a81e-5f68-11e6-aa03-5cc5d4d378cb');
